			mockBigQueryService.fetchStyleCopurchases.mockImplementation(async () => {
				(command as unknown as { isShuttingDown: boolean }).isShuttingDown = true;
				throw new Error('interrupted');
			});

			await command.run();

			expect(processExitSpy).not.toHaveBeenCalledWith(1);
		});
	});

	describe('handleShutdown', () => {
		it('should set isShuttingDown and exit with 0 when no current operation', async () => {
			await (
				command as unknown as {
					handleShutdown: (params: { signal: string }) => Promise<void>;
				}
			).handleShutdown({ signal: 'SIGTERM' });

