			let resolveOp: () => void;
			(
				command as unknown as { currentOperation: Promise<void> | null }
			).currentOperation = new Promise<void>((resolve) => {
				resolveOp = resolve;
			});

			const shutdownPromise = (
				command as unknown as {
					handleShutdown: (params: { signal: string }) => Promise<void>;
				}
			).handleShutdown({ signal: 'SIGTERM' });

			jest.advanceTimersByTime(30000);

